1	type Cell = string;
2	
3	const keyOf = (x: number, y: number): Cell => `${x},${y}`;
4	
5	const parseCell = (cell: Cell): [number, number] => {
6	  const [x, y] = cell.split(",").map(Number);
7	  return [x, y];
8	};
9	
10	const neighborsOf = (cell: Cell): Cell[] => {
11	  const [x, y] = parseCell(cell);
12	  const neighbors: Cell[] = [];
13	  for (let dx = -1; dx <= 1; dx++) {
14	    for (let dy = -1; dy <= 1; dy++) {
15	      if (dx === 0 && dy === 0) continue;
16	      neighbors.push(keyOf(x + dx, y + dy));
17	    }
18	  }
19	  return neighbors;
20	};
21	
22	const countLiveNeighbors = (cell: Cell, livingCells: Set<Cell>): number =>
23	  neighborsOf(cell).filter((neighbor) => livingCells.has(neighbor)).length;
24	
25	const candidateCells = (livingCells: Set<Cell>): Set<Cell> => {
26	  const candidates = new Set<Cell>();
27	  for (const cell of livingCells) {
28	    candidates.add(cell);
29	    for (const neighbor of neighborsOf(cell)) candidates.add(neighbor);
30	  }
31	  return candidates;
32	};
33	
34	const survives = (cell: Cell, livingCells: Set<Cell>): boolean => {
35	  const liveNeighbors = countLiveNeighbors(cell, livingCells);
36	  const isAlive = livingCells.has(cell);
37	  if (isAlive) return liveNeighbors === 2 || liveNeighbors === 3;
38	  return liveNeighbors === 3;
39	};
40	
41	export function nextGeneration(livingCells: Set<Cell>): Set<Cell> {
42	  const next = new Set<Cell>();
43	  for (const cell of candidateCells(livingCells)) {
44	    if (survives(cell, livingCells)) next.add(cell);
45	  }
46	  return next;
47	}
