1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life", () => {
5	  it("should return an empty set when given an empty set of living cells", () => {
6	    expect(nextGeneration(new Set())).toEqual(new Set());
7	  });
8	  it("should return an empty set when a single living cell has no neighbors (underpopulation)", () => {
9	    expect(nextGeneration(new Set(["0,0"]))).toEqual(new Set());
10	  });
11	  it("should kill a living cell with only one live neighbor (underpopulation)", () => {
12	    // Three cells: (5,5) has 1 neighbor -> dies; (5,5)'s only neighbor (6,5) has 2 neighbors;
13	    // Use simpler isolated pair: two diagonal cells far from anything else with 1 neighbor each
14	    // To force non-trivial failure, add a known stable 2x2 block far away that survives
15	    const input = new Set(["0,0", "1,0", "10,10", "11,10", "10,11", "11,11"]);
16	    const expected = new Set(["10,10", "11,10", "10,11", "11,11"]);
17	    expect(nextGeneration(input)).toEqual(expected);
18	  });
19	  it("should keep a living cell alive when it has two live neighbors (survival)", () => {
20	    // A vertical line of 3 cells (blinker): middle cell has 2 live neighbors, survives
21	    // The two end cells have 1 neighbor each, so they die.
22	    // The two horizontal cells (left and right of middle) each have 3 live neighbors, become alive.
23	    // To isolate the survival rule, we need to construct a scenario where a living cell with
24	    // exactly 2 neighbors survives. Use an L-shape: (0,0), (1,0), (0,1) where (0,0) has 2 neighbors.
25	    // (0,0) -> 2 neighbors (1,0) and (0,1) -> survives
26	    // (1,0) -> 1 neighbor (0,0) -> dies
27	    // (0,1) -> 1 neighbor (0,0) -> dies
28	    // (1,1) dead -> 3 neighbors (0,0), (1,0), (0,1) -> becomes alive
29	    // So result includes (0,0) which is the survival case
30	    const input = new Set(["0,0", "1,0", "0,1"]);
31	    const result = nextGeneration(input);
32	    expect(result.has("0,0")).toBe(true);
33	  });
34	  it.todo("should keep a living cell alive when it has three live neighbors (survival)");
35	  it.todo("should kill a living cell with four live neighbors (overpopulation)");
36	  it.todo("should bring a dead cell to life when it has exactly three live neighbors (reproduction)");
37	  it.todo("should handle living cells with negative coordinates");
38	});
